&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Clearly, Suresh&amp;#39;s favorite subject is &amp;#39;English&amp;#39;.&lt;/p&gt;

&lt;div style=&quot;color: rgb(33, 37, 41);&quot;&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;English&amp;quot;.&lt;/span&gt;&lt;/div&gt;<br><br>&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;दी गई जानकारी के अनुसार,&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;चिंटू, पिंटू, सुरेश, रमेश और महेश एक कक्षा में पाँच मित्र हैं। उनमें से प्रत्येक को एक अलग विषय जैसे हिंदी, अंग्रेजी, गणित, विज्ञान और कला &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;पसंद है&lt;/span&gt;, लेकिन जरूरी नहीं कि इसी क्रम में है। उनमें से प्रत्येक एक अलग कक्षा अर्थात I, II, III, IV और V &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;में पढ़ता है&lt;/span&gt;, लेकिन जरूरी नहीं कि इसी क्रम में हैं।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;पिंटू कक्षा I&amp;nbsp;में पढ़ता है और उसे गणित विषय पसंद है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अंग्रेजी विषय पसंद करने वाला&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;व्यक्ति&lt;/span&gt; कक्षा V में पढ़ता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;महेश कक्षा IV&amp;nbsp;में पढ़ता है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color: rgb(33, 37, 41); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align); width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td rowspan=&quot;2&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कक्ष&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td colspan=&quot;1&quot; rowspan=&quot;1&quot; style=&quot;text-align: center;&quot;&gt;&lt;b&gt;विषय&amp;nbsp;&lt;/b&gt;&lt;/td&gt;
			&lt;td rowspan=&quot;1&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;व्यक्ति&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;1&quot; rowspan=&quot;2&quot; style=&quot;text-align: center;&quot;&gt;गणित&amp;nbsp;&lt;/td&gt;
			&lt;td rowspan=&quot;2&quot; style=&quot;text-align: center;&quot;&gt;पिंटू&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;I&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;II&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;III&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;IV&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;महेश&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;V&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;अंग्रेजी&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;रमेश को कला विषय पसंद है और वह न तो कक्षा I और न ही कक्षा II में पढ़ता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चिंटू को विज्ञान या अंग्रेजी विषय पसंद नहीं है।&lt;/strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt; &lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color: rgb(33, 37, 41); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align); width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td rowspan=&quot;2&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कक्ष&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td colspan=&quot;1&quot; rowspan=&quot;1&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विषय&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td rowspan=&quot;1&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;व्यक्ति&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;1&quot; rowspan=&quot;2&quot; style=&quot;text-align: center;&quot;&gt;गणित&amp;nbsp;&lt;/td&gt;
			&lt;td rowspan=&quot;2&quot; style=&quot;text-align: center;&quot;&gt;पिंटू&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;I&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;II&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;हिंदी&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;चिंटू&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;III&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कला&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;रमेश&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;IV&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;विज्ञान&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;महेश&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;V&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;अंग्रेजी&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;सुरेश&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;स्पष्टतः, सुरेश का पसंदीदा विषय &amp;#39;अंग्रेजी&amp;#39; है।&lt;/p&gt;

&lt;p&gt;अतः&amp;nbsp;सही उत्तर &lt;strong&gt;&amp;quot;अंग्रेजी&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Drawing the diagram according to the given information,&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/05/F2_Vinanti_State%20govt._11.05.23_D1.png&quot; style=&quot;width: 420px; height: 323px;&quot; /&gt;&lt;br /&gt;
The distance between the final and the initial point can be found by the Pythagoras theorem.&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(Hypotenuse)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;= (Base)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;+ (Perpendicular)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;.&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(H)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;= (60)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;+ (80)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(H)&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;= 3600 + 6400&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(H)&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;= 10000&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;H = 100m.&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Therefore, the distance between his tutor&amp;#39;s home from his home is&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;100m&amp;quot;.&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;Option2: &lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); font-weight: 700;&quot;&gt;100m&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;.&lt;/span&gt;&lt;/p&gt;<br><br>&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;दी गई जानकारी के अनुसार आरेख बनाने पर,&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/05/F2_Vinanti_State%20govt._11.05.23_D1.png&quot; style=&quot;width: 420px; height: 323px;&quot; /&gt;&lt;br /&gt;
पाइथागोरस प्रमेय द्वारा अंतिम और प्रारंभिक बिंदु के बीच की दूरी ज्ञात की जा सकती है।&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(कर्ण)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;= (आधार)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;+ (लंब)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(H)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;= (60)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;+ (80)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(H)&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;= 3600 + 6400&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;(H)&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;= 10000&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;H = 100 मीटर&lt;/p&gt;

&lt;p&gt;इसलिए, उसके शिक्षक के घर से उसके घर की दूरी &lt;strong&gt;&amp;quot;100 &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;मीटर&lt;/span&gt;&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;अतः सही उत्तर &lt;strong&gt;&amp;quot;विकल्प 2: 100 &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;मीटर&lt;/span&gt;&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;The diagram according to the given information is:&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/08/F1_State%20G_Arbaz_8-8-23_D16.png&quot; style=&quot;width: 418px; height: 323px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;So, My friend is travelling in now &amp;#39;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;South to North&lt;/span&gt;&amp;#39; direction.&lt;/p&gt;

&lt;p&gt;Hence, the correct answer is &lt;strong&gt;&amp;quot;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;South to North&lt;/span&gt;&amp;quot;&lt;/strong&gt;.&lt;/p&gt;<br><br>&lt;p&gt;दी गई जानकारी के अनुसार आरेख निम्नानुसार है:&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/08/F1_State%20G_Arbaz_8-8-23_D16.png&quot; style=&quot;color: rgb(33, 37, 41); width: 418px; height: 323px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;इसलिए, मेरा मित्र अब &amp;#39;दक्षिण से उत्तर&amp;#39; दिशा में यात्रा कर रहा है।&lt;/p&gt;

&lt;p&gt;अतः&amp;nbsp;सही उत्तर &lt;strong&gt;&amp;quot;दक्षिण से उत्तर&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;According to the given information:&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/22/08/F4_Madhuri_State%20Govt._26.08.2022_D12.png&quot; style=&quot;width: 145px; height: 283px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;Number of students in class =&lt;strong&gt; Rank of Pallavi from top + rank of Pallavi from bottom - 1&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;= 16 + 29 - 1&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;= 44&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;Hence, the correct answer is&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;quot;44&amp;quot;.&lt;/span&gt;&lt;/p&gt;<br><br>&lt;p&gt;दी हुई जानकारी के अनुसार:&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/22/08/F4_Madhuri_State%20Govt._26.08.2022_D12.png&quot; style=&quot; width: 145px; height: 283px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;कक्षा में विद्यार्थीयों की संख्या = ऊपर से पल्लवी की रैंक + नीचे से पल्लवी की रैंक - 1&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;= 16 + 29 - 1&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;= 44&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;अत: सही उत्तर &lt;strong&gt;&amp;quot;44&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;

questions.statement:
&lt;p&gt;Select the option that is related to the fourth term in the same way as the first term is related to the second term and the fifth term is related to the sixth term.&lt;/p&gt;

&lt;p&gt;4 : 33&amp;nbsp;:: ?&amp;nbsp;:&amp;nbsp;109 :: 8 : 257&lt;/p&gt;<br>&lt;p&gt;उस विकल्प का चयन कीजिए&amp;nbsp;जो चौथे पद से उसी प्रकार संबंधित है जिस प्रकार&amp;nbsp;पहला पद, दूसरे पद से संबंधित है और पाँचवाँ&amp;nbsp;पद, छठे पद से संबंधित है।&lt;/p&gt;

&lt;p&gt;4 : 33&amp;nbsp;:: ?&amp;nbsp;:&amp;nbsp;109 :: 8 : 257&lt;/p&gt;

questions.explanation:
&lt;p&gt;&lt;strong&gt;Given:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;4 : 33&amp;nbsp;:: ?&amp;nbsp;:&amp;nbsp;109 :: 8 : 257&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Logic: Second number = [{(First no.)&lt;sup&gt;3&lt;/sup&gt; + 2}&amp;nbsp;&amp;divide; 2]&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;4 : 33&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; [{(4)&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ 2}&amp;nbsp;&amp;divide; 2]&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [(64 + 2)&amp;nbsp;&amp;divide; 2]&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (66&amp;nbsp;&amp;divide; 2) = 33&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;8 : 257&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [{(8)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ 2}&amp;nbsp;&amp;divide; 2]&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [(512&amp;nbsp;+ 2)&amp;nbsp;&amp;divide; 2]&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (514&amp;nbsp;&amp;divide; 2) = 257&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Similarly, for &amp;#39;? : 109&amp;#39;&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [{(Y)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ 2}&amp;nbsp;&amp;divide; 2] = 109&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [{(Y)&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;+ 2}] = (109&amp;nbsp;&amp;times; 2)&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (Y)&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;= 218 - 2&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (Y)&lt;/span&gt;&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;= 216&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr;&lt;strong&gt; Y = 6&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;Here, &lt;strong&gt;&amp;#39;6 : 109&amp;#39;&lt;/strong&gt; is the correct pair.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;Hence, the correct answer is&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;Option (3)&amp;quot;.&lt;/span&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;दिया गया है:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;4 : 33&amp;nbsp;:: ?&amp;nbsp;:&amp;nbsp;109 :: 8 : 257&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;तर्क: दूसरी संख्या&amp;nbsp;= [{(पहली संख्या)&lt;sup&gt;3&lt;/sup&gt; + 2}&amp;nbsp;&amp;divide; 2]&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;4 : 33&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; [{(4)&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ 2}&amp;nbsp;&amp;divide; 2]&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [(64 + 2)&amp;nbsp;&amp;divide; 2]&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (66&amp;nbsp;&amp;divide; 2) = 33&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;8 : 257&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [{(8)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ 2}&amp;nbsp;&amp;divide; 2]&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [(512&amp;nbsp;+ 2)&amp;nbsp;&amp;divide; 2]&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (514&amp;nbsp;&amp;divide; 2) = 257&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;इसी तरह, &amp;#39;? : 109&amp;#39; के लिए&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [{(Y)&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ 2}&amp;nbsp;&amp;divide; 2] = 109&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; [{(Y)&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;+ 2}] = (109&amp;nbsp;&amp;times; 2)&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (Y)&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;= 218 - 2&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; (Y)&lt;/span&gt;&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;= 216&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr;&lt;strong&gt; Y = 6&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;यहाँ, &lt;strong&gt;&amp;#39;6 : 109&amp;#39;&lt;/strong&gt;&amp;nbsp;सही युग्म है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;अतः&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;सही उत्तर&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;विकल्प (3)&amp;quot;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Given:&lt;/p&gt;

&lt;p&gt;A is 40 m south-west of B. C is 40 m south-east of B.&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/25/09/IMG-1232-Arpit-6.png&quot; style=&quot;width: 360px; height: 268px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;Thus,&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;C is to the east of A.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Hence, &lt;strong&gt;&amp;quot;Option 4&amp;quot;&lt;/strong&gt; is the correct answer.&lt;/p&gt;<br><br>&lt;p&gt;दिया गया है:&lt;/p&gt;

&lt;p&gt;A, B के 40 मीटर दक्षिण-पश्चिम में है। C, B के 40 मीटर दक्षिण-पूर्व में है।&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/25/09/IMG-1232-Arpit-6.png&quot; style=&quot;color: rgb(33, 37, 41); width: 360px; height: 268px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;इस प्रकार, &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;C, A के पूर्व में है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;इसलिए, &lt;strong&gt;&amp;quot;विकल्प 4&amp;quot;&lt;/strong&gt; सही उत्तर है।&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage640dc90d2ebe070729f6bb9d.png&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;The logic followed here is:&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;For, &amp;#39;IKLN&amp;#39; is related to &amp;#39;FHIK&amp;#39;&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/24/01/F1_SSC_Priyas_15-01-24_D18.png&quot; style=&quot;width: 127px; height: 136px;&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;For,&amp;nbsp;&amp;#39;GIJL&amp;#39; is related to &amp;#39;DFGI&amp;#39;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/24/01/F1_SSC_Priyas_15-01-24_D19.png&quot; style=&quot;width: 127px; height: 89px;&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Similarly, for&amp;nbsp;&amp;#39;&lt;strong&gt;MOPR&lt;/strong&gt;&amp;#39;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/24/01/F1_SSC_Priyas_15-01-24_D20.png&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;So,&amp;nbsp;&amp;#39;&lt;span style=&quot;font-weight: bolder;&quot;&gt;MOPR&lt;/span&gt;&amp;#39; will be&amp;nbsp;related to &amp;#39;&lt;span style=&quot;font-weight: bolder;&quot;&gt;JLMO&lt;/span&gt;&amp;#39;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;Option 3&amp;quot;&lt;/span&gt;.&lt;/p&gt;<br><br>&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage640dc90d2ebe070729f6bb9d.png&quot; /&gt;&lt;/p&gt;

&lt;p&gt;यहाँ अनुसरण किया गया तर्क निम्न है:&lt;/p&gt;

&lt;p&gt;&amp;#39;IKLN&amp;#39;, &amp;#39;FHIK&amp;#39; से संबंधित है,&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/24/01/F1_SSC_Priyas_15-01-24_D18.png&quot; style=&quot;color: rgb(33, 37, 41); width: 127px; height: 136px;&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;#39;GIJL&amp;#39;, &amp;#39;DFGI&amp;#39; से संबंधित है,&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/24/01/F1_SSC_Priyas_15-01-24_D19.png&quot; style=&quot;color: rgb(33, 37, 41); width: 127px; height: 89px;&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;इसी प्रकार, &amp;#39;&lt;strong&gt;MOPR&lt;/strong&gt;&amp;#39; के लिए,&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/24/01/F1_SSC_Priyas_15-01-24_D20.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; /&gt;&lt;/p&gt;

&lt;p&gt;इसलिए, &lt;strong&gt;&amp;#39;MOPR&amp;#39;&lt;/strong&gt;, &lt;strong&gt;&amp;#39;JLMO&amp;#39;&lt;/strong&gt; से संबंधित होगा&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;अतः, सही उत्तर &lt;strong&gt;&amp;quot;विकल्प 3&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;

